import React, { useState, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const initialLR = 0.1;
const maxEpochs = 30;

export default function App() {
  const [gamma, setGamma] = useState(0.5);
  const [stepSize, setStepSize] = useState(5);
  const [hoveredEpoch, setHoveredEpoch] = useState(null);

  const schedule = useMemo(() => {
    return Array.from({ length: maxEpochs }, (_, epoch) => {
      const numDecays = Math.floor(epoch / stepSize);
      const lr = initialLR * Math.pow(gamma, numDecays);
      return { epoch, lr: Math.round(lr * 10000) / 10000, numDecays };
    });
  }, [gamma, stepSize]);

  const W = 560, H = 260;
  const pad = { t: 24, r: 50, b: 38, l: 58 };
  const plotW = W - pad.l - pad.r;
  const plotH = H - pad.t - pad.b;

  const yMax = initialLR * 1.12;
  const yMin = 0;

  const toX = (epoch) => pad.l + (epoch / (maxEpochs - 1)) * plotW;
  const toY = (lr) => pad.t + (1 - (lr - yMin) / (yMax - yMin)) * plotH;

  const staircasePath = useMemo(() => {
    if (schedule.length === 0) return '';
    let d = 'M ' + toX(0) + ' ' + toY(schedule[0].lr);
    for (let i = 1; i < schedule.length; i++) {
      const prevLR = schedule[i - 1].lr;
      const curLR = schedule[i].lr;
      const x = toX(i);
      if (curLR !== prevLR) {
        d += ' L ' + x + ' ' + toY(prevLR);
        d += ' L ' + x + ' ' + toY(curLR);
      } else {
        d += ' L ' + x + ' ' + toY(curLR);
      }
    }
    return d;
  }, [schedule]);

  const fillPath = useMemo(() => {
    if (!staircasePath) return '';
    const bottomY = toY(0);
    return staircasePath + ' L ' + toX(maxEpochs - 1) + ' ' + bottomY + ' L ' + toX(0) + ' ' + bottomY + ' Z';
  }, [staircasePath]);

  const stepBoundaries = useMemo(() => {
    const bounds = [];
    for (let i = 1; i < schedule.length; i++) {
      if (schedule[i].numDecays !== schedule[i - 1].numDecays) {
        bounds.push(i);
      }
    }
    return bounds;
  }, [schedule]);

  const hoveredInfo = hoveredEpoch !== null ? schedule[hoveredEpoch] : null;

  const yTicks = [0, 0.025, 0.05, 0.075, 0.1];

  const getInsight = () => {
    if (gamma >= 0.9) return 'Gamma near 1.0 means almost no decay. The model keeps taking large steps, risking oscillation around the optimum instead of converging precisely.';
    if (gamma <= 0.15) return 'Gamma is very small -- the LR drops dramatically at each step! The model essentially stops learning after a few decays. Too aggressive for most training.';
    if (stepSize >= 12) return 'Large step size = long plateaus at each LR. Good when you need extended exploration before slowing down, but you get fewer total decays.';
    if (stepSize <= 2) return 'Tiny step size = frequent decays. The LR drops rapidly, shifting from exploration to fine-tuning very quickly. Risk: the model may not learn enough at each stage.';
    if (hoveredInfo && hoveredInfo.numDecays >= 3) return 'After ' + hoveredInfo.numDecays + ' decays, the LR is just ' + hoveredInfo.lr + '. The model is now making tiny adjustments -- fine-tuning toward a precise minimum.';
    return 'The staircase shape is key: fast learning early (high LR) then automatic fine-tuning (low LR). Compare with the dashed "no decay" line to see how much the schedule slows training over time.';
  };

  return (
    <div style={{
      background: theme.colors.background,
      minHeight: '100vh',
      padding: '16px',
      fontFamily: theme.font,
      color: theme.colors.text,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
    }}>
      <div style={{ maxWidth: 600, width: '100%' }}>
        <div style={{ marginBottom: '10px' }}>
          <div style={{ fontSize: '18px', fontWeight: '700' }}>StepLR Scheduler</div>
          <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>
            Drag gamma to reshape the decay staircase. Hover any epoch to trace the math.
          </div>
        </div>

        <div style={{
          display: 'flex',
          gap: '20px',
          marginBottom: '10px',
          padding: '10px 14px',
          background: theme.colors.surface,
          borderRadius: '8px',
          border: '1px solid ' + theme.colors.border,
          alignItems: 'center',
        }}>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: '11px', color: theme.colors.textSecondary, marginBottom: '5px' }}>
              Gamma: <span style={{ color: theme.colors.yellow, fontWeight: 700, fontSize: '13px' }}>{gamma.toFixed(2)}</span>
            </div>
            <input
              type="range"
              min="0.05"
              max="0.95"
              step="0.05"
              value={gamma}
              onChange={(e) => setGamma(parseFloat(e.target.value))}
              style={{ width: '100%', accentColor: theme.colors.yellow, cursor: 'pointer' }}
            />
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '9px', color: theme.colors.textMuted }}>
              <span>aggressive</span>
              <span>gentle</span>
            </div>
          </div>
          <div style={{ width: 1, height: 40, background: theme.colors.border }} />
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: '11px', color: theme.colors.textSecondary, marginBottom: '5px' }}>
              Step Size: <span style={{ color: theme.colors.blue, fontWeight: 700, fontSize: '13px' }}>{stepSize}</span> epochs
            </div>
            <input
              type="range"
              min="2"
              max="15"
              step="1"
              value={stepSize}
              onChange={(e) => setStepSize(parseInt(e.target.value))}
              style={{ width: '100%', accentColor: theme.colors.blue, cursor: 'pointer' }}
            />
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '9px', color: theme.colors.textMuted }}>
              <span>frequent</span>
              <span>rare</span>
            </div>
          </div>
          <div style={{ width: 1, height: 40, background: theme.colors.border }} />
          <div style={{ textAlign: 'center', minWidth: 60 }}>
            <div style={{ fontSize: '9px', color: theme.colors.textMuted }}>Initial LR</div>
            <div style={{ fontSize: '16px', fontWeight: 700, color: theme.colors.blue }}>{initialLR}</div>
          </div>
        </div>

        <div style={{
          background: theme.colors.surface,
          borderRadius: '10px',
          border: '1px solid ' + theme.colors.border,
          padding: '6px 6px 2px 6px',
        }}>
          <svg
            width="100%"
            viewBox={'0 0 ' + W + ' ' + H}
            style={{ display: 'block' }}
            onMouseLeave={() => setHoveredEpoch(null)}
          >
            <defs>
              <linearGradient id="fillGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={theme.colors.green} stopOpacity="0.15" />
                <stop offset="100%" stopColor={theme.colors.green} stopOpacity="0.02" />
              </linearGradient>
            </defs>

            {yTicks.map((val, i) => (
              <g key={'yt' + i}>
                <line
                  x1={pad.l} y1={toY(val)}
                  x2={W - pad.r} y2={toY(val)}
                  stroke={theme.colors.border}
                  strokeWidth={val === 0 ? 1 : 0.5}
                  strokeDasharray={val === 0 ? 'none' : '3,3'}
                />
                <text
                  x={pad.l - 8}
                  y={toY(val) + 3.5}
                  textAnchor="end"
                  fontSize="9.5"
                  fill={theme.colors.textSecondary}
                  fontFamily={theme.font}
                >
                  {val.toFixed(3)}
                </text>
              </g>
            ))}

            {[0, 5, 10, 15, 20, 25, 29].map((ep) => (
              <text
                key={'xt' + ep}
                x={toX(ep)}
                y={H - pad.b + 18}
                textAnchor="middle"
                fontSize="9.5"
                fill={theme.colors.textSecondary}
                fontFamily={theme.font}
              >
                {ep}
              </text>
            ))}

            <text
              x={W / 2}
              y={H - 2}
              textAnchor="middle"
              fontSize="10"
              fill={theme.colors.textMuted}
              fontFamily={theme.font}
            >
              Epoch
            </text>

            <line
              x1={pad.l} y1={toY(initialLR)}
              x2={W - pad.r} y2={toY(initialLR)}
              stroke={theme.colors.textMuted}
              strokeWidth={1}
              strokeDasharray="6,4"
              opacity={0.5}
            />
            <text
              x={W - pad.r + 4}
              y={toY(initialLR) + 3}
              fontSize="8.5"
              fill={theme.colors.textMuted}
              fontFamily={theme.font}
            >
              no decay
            </text>

            <path d={fillPath} fill="url(#fillGrad)" />

            <path
              d={staircasePath}
              fill="none"
              stroke={theme.colors.green}
              strokeWidth={2.5}
              strokeLinejoin="round"
            />

            {stepBoundaries.slice(0, 5).map((epoch) => {
              const cx = toX(epoch);
              const prevLR = schedule[epoch - 1].lr;
              const curLR = schedule[epoch].lr;
              const midY = (toY(prevLR) + toY(curLR)) / 2;
              return (
                <g key={'sb' + epoch}>
                  <line
                    x1={cx} y1={toY(prevLR) + 2}
                    x2={cx} y2={toY(curLR) - 2}
                    stroke={theme.colors.pink}
                    strokeWidth={1.5}
                    strokeDasharray="2,2"
                    opacity={0.6}
                  />
                  <text
                    x={cx + 8}
                    y={midY + 3}
                    fontSize="8.5"
                    fill={theme.colors.pink}
                    fontFamily={theme.font}
                    fontWeight="600"
                    opacity={0.85}
                  >
                    {'x' + gamma}
                  </text>
                </g>
              );
            })}

            {schedule.map((s, i) => {
              const cx = toX(s.epoch);
              const cy = toY(s.lr);
              const isHovered = hoveredEpoch === i;
              const isBoundary = stepBoundaries.includes(i);
              return (
                <g key={'ep' + i}>
                  <rect
                    x={cx - plotW / (maxEpochs - 1) / 2}
                    y={pad.t}
                    width={plotW / (maxEpochs - 1)}
                    height={plotH}
                    fill="transparent"
                    onMouseEnter={() => setHoveredEpoch(i)}
                    style={{ cursor: 'crosshair' }}
                  />
                  {isHovered && (
                    <line
                      x1={cx} y1={pad.t}
                      x2={cx} y2={pad.t + plotH}
                      stroke={theme.colors.yellow}
                      strokeWidth={1}
                      strokeDasharray="3,3"
                      opacity={0.35}
                    />
                  )}
                  <circle
                    cx={cx}
                    cy={cy}
                    r={isHovered ? 5.5 : isBoundary ? 3.5 : 2}
                    fill={isHovered ? theme.colors.yellow : isBoundary ? theme.colors.pink : theme.colors.green}
                    opacity={isHovered ? 1 : isBoundary ? 0.9 : 0.7}
                  />
                  {isHovered && (
                    <line
                      x1={pad.l} y1={cy}
                      x2={cx} y2={cy}
                      stroke={theme.colors.yellow}
                      strokeWidth={1}
                      strokeDasharray="3,3"
                      opacity={0.3}
                    />
                  )}
                </g>
              );
            })}
          </svg>
        </div>

        <div style={{
          marginTop: '8px',
          padding: '10px 14px',
          background: theme.colors.surface,
          borderRadius: '8px',
          border: '1px solid ' + theme.colors.border,
          minHeight: '48px',
          transition: 'all 0.15s ease',
        }}>
          {hoveredInfo ? (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.textSecondary, marginBottom: '3px' }}>
                Epoch <span style={{ color: theme.colors.yellow, fontWeight: 700 }}>{hoveredInfo.epoch}</span>
                {' -- '}
                <span style={{ color: theme.colors.pink, fontWeight: 600 }}>{hoveredInfo.numDecays}</span>
                {' decay'}{hoveredInfo.numDecays !== 1 ? 's' : ''} applied
                {hoveredInfo.numDecays > 0 ? ' (floor(' + hoveredInfo.epoch + '/' + stepSize + ') = ' + hoveredInfo.numDecays + ')' : ''}
              </div>
              <div style={{ fontSize: '13px' }}>
                <span style={{ color: theme.colors.textSecondary }}>LR = </span>
                <span style={{ color: theme.colors.blue }}>{initialLR}</span>
                <span style={{ color: theme.colors.textMuted }}> * </span>
                <span style={{ color: theme.colors.yellow }}>{gamma}</span>
                <span style={{ color: theme.colors.textMuted }}>^</span>
                <span style={{ color: theme.colors.pink }}>{hoveredInfo.numDecays}</span>
                <span style={{ color: theme.colors.textMuted }}> = </span>
                <span style={{ color: theme.colors.blue }}>{initialLR}</span>
                <span style={{ color: theme.colors.textMuted }}> * </span>
                <span style={{ color: theme.colors.yellow }}>{(Math.pow(gamma, hoveredInfo.numDecays)).toFixed(4)}</span>
                <span style={{ color: theme.colors.textMuted }}> = </span>
                <span style={{ color: theme.colors.green, fontWeight: 700, fontSize: '14px' }}>{hoveredInfo.lr}</span>
              </div>
            </div>
          ) : (
            <div style={{ fontSize: '12px', color: theme.colors.textMuted, paddingTop: 4 }}>
              Hover over any epoch point to see the exact computation step by step
            </div>
          )}
        </div>

        <div style={{
          marginTop: '8px',
          padding: '10px 14px',
          background: theme.colors.surfaceAlt,
          borderRadius: '8px',
          fontSize: '11px',
          color: theme.colors.textSecondary,
          borderLeft: '4px solid ' + theme.colors.primary,
          lineHeight: 1.55,
        }}>
          <span style={{ color: theme.colors.primary, fontWeight: '600' }}>Insight: </span>
          {getInsight()}
        </div>
      </div>
    </div>
  );
}

